VALUES
  ('elementary-f29af906-moex-00878', 'elementary-f29af906', 'elementary-f29af906-moex-110-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依司法院釋字第779號解釋，下列敘述何者正確？', '["都市計畫法指定之公共設施保留地，尚未被徵收前之移轉免徵土地增值稅；非都市土地地目為道之交 通用地，尚未被徵收前之移轉免徵土地增值稅", "都市計畫法指定之公共設施保留地，尚未被徵收前之移轉應課徵土地增值稅；非都市土地地目為道之 交通用地，尚未被徵收前之移轉應課徵土地增值稅", "都市計畫法指定之公共設施保留地，尚未被徵收前之移轉應課徵土地增值稅；非都市土地地目為道之 交通用地，尚未被徵收前之移轉免徵土地增值稅", "都市計畫法指定之公共設施保留地，尚未被徵收前之移轉免徵土地增值稅；非都市土地地目為道之交 通用地，尚未被徵收前之移轉應課徵土地增值稅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:56+00:00", "source_pdf_sha1": "adea1da9374e", "answer_pdf_sha1": "4b828ac3b6b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00879', 'elementary-f29af906', 'elementary-f29af906-moex-110-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '土地登記案件經依法駁回者，其已繳之登記費與書狀費之處理，依土地登記規則規定，下列敘述何者錯 誤？', '["申請人於十年內重新申請登記者，得予援用未申請退還之登記費與書狀費", "申請人未於一年內申請退還登記費與書狀費者，於十年內重新申請登記時，不得援用已繳納之登記費 與書狀費", "已繳之登記費得由申請人於十年內請求退還", "已繳之書狀費得由申請人於十年內請求退還"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:56+00:00", "source_pdf_sha1": "adea1da9374e", "answer_pdf_sha1": "4b828ac3b6b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00880', 'elementary-f29af906', 'elementary-f29af906-moex-110-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依市地重劃實施辦法規定，有關重劃區供公共使用之十項用地以外之公共設施用地，是否列為共同負擔 之同意原則，下列敘述何者正確？', '["應由重劃區全體所有權人同意始得列為共同負擔", "應由重劃區所有權人逾四分之三，所有土地面積逾四分之三之同意始得列為共同負擔", "應由重劃區所有權人逾三分之二，所有土地面積逾三分之二之同意始得列為共同負擔", "應由重劃區所有權人逾二分之一，所有土地面積逾二分之一之同意始得列為共同負擔"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:56+00:00", "source_pdf_sha1": "adea1da9374e", "answer_pdf_sha1": "4b828ac3b6b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00881', 'elementary-f29af906', 'elementary-f29af906-moex-110-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '申請人依國土計畫法規定申請使用許可，下列敘述何者錯誤？', '["使用許可不得變更國土功能分區、分類", "填海造地案件限於城鄉發展地區申請", "直轄市、縣（市）主管機關受理申請後應於審議後辦理公開展覽及舉行公聽會", "國土保育地區之使用許可申請案件由內政部審議"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:56+00:00", "source_pdf_sha1": "adea1da9374e", "answer_pdf_sha1": "4b828ac3b6b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00882', 'elementary-f29af906', 'elementary-f29af906-moex-110-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依都市更新條例第58條規定，權利變換範圍內之租賃契約，若因權利變換不能達成原租賃之目的而終止 租約，在租賃契約未有特別規定之情形下，其處理方式，下列敘述何者正確？', '["出租土地係供為建築房屋者，所餘租期未滿一年者，承租人得向出租人請求相當一年租金之補償", "訂有耕地三七五租約者，出租人應給付承租人相當一年租金之補償", "於出租房屋之情形，不問所餘租期長短，承租人一律得向出租人請求相當二個月租金之補償", "出租土地非屬供為建築房屋之情形，所餘租期未滿一年者，承租人得向出租人請求相當一年租金之補償"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:56+00:00", "source_pdf_sha1": "adea1da9374e", "answer_pdf_sha1": "4b828ac3b6b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00883', 'elementary-f29af906', 'elementary-f29af906-moex-110-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '因都市計畫違法而受損害之人民，為請求宣告都市計畫無效，依行政訴訟法規定，應以何者為被告？', '["都市計畫執行機關", "都市計畫擬定機關", "都市計畫核定機關", "都市計畫備案機關"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:56+00:00", "source_pdf_sha1": "adea1da9374e", "answer_pdf_sha1": "4b828ac3b6b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00884', 'elementary-f29af906', 'elementary-f29af906-moex-110-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '下列關於單獨申請登記，何者敘述錯誤？', '["區分所有建物，區分所有權人得就其專有部分及所屬共有部分之權利，單獨申請建物所有權第一次登記", "同一標的之普通抵押權，因次序讓與申請權利內容變更登記者，得由受讓人單獨申請之", "同一標的之普通抵押權，因次序拋棄申請權利內容變更登記者，得由拋棄人單獨申請之", "承攬人申請預為抵押權登記，承攬契約經公證後，承攬人得單獨申請之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:56+00:00", "source_pdf_sha1": "adea1da9374e", "answer_pdf_sha1": "4b828ac3b6b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00885', 'elementary-f29af906', 'elementary-f29af906-moex-110-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地登記規則之相關規定，下列敘述何者正確？', '["土地權利因混同而消滅者應申請辦理塗銷登記", "權利人之姓名有變更者應申請辦理更正登記", "信託專簿應自塗銷信託登記之日起保存五年", "以胎兒為繼承人所為登記之權利，若胎兒將來為死產者，應自其他繼承人共同申請更正登記時起向後 失效"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:56+00:00", "source_pdf_sha1": "adea1da9374e", "answer_pdf_sha1": "4b828ac3b6b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00886', 'elementary-f29af906', 'elementary-f29af906-moex-110-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '關於因徵收取得土地權利之情形，下列敘述何者正確？', '["非經登記不生效力", "直轄市地政機關應於補償完竣後一個月內囑託登記機關為所有權登記", "應於預告登記塗銷後始得登記", "徵收為法律行為"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:56+00:00", "source_pdf_sha1": "adea1da9374e", "answer_pdf_sha1": "4b828ac3b6b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00887', 'elementary-f29af906', 'elementary-f29af906-moex-110-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '我國現行土地徵收之地價補償價額，下列何者正確？', '["依公告地價", "依徵收當期之市價補償", "依公告現值補償", "依公告現值加成補償"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:56+00:00", "source_pdf_sha1": "adea1da9374e", "answer_pdf_sha1": "4b828ac3b6b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL)
